def compute_cost_per_seat_day(c,day):
    if c['type']=='large': units=ent_usage_per_seat_day(c['g'],c['plan'])
    else: units=usage_per_seat_day.get((c['g'],c['plan']), {'A':165,'B':170,'C':180}.get(c['plan'],170))
    return units*tier_rate(c['plan'],day)

def simulate(days,seed):
    rng=random.Random(seed)
    scenario=max(-1.8,min(1.8,rng.gauss(0,0.65)))
    cash=cash0
    active=[c.copy() for c in coh+ent]
    events=ent_events(days,rng,scenario)
    for day in range(DAY+1,DAY+days+1):
        rel=day-DAY
        for e in [x for x in events if x['day']==day]:
            cash += e['price']*e['seats']
            active.append(e.copy())
        active_s2=sum(c['seats'] for c in active if c['g']=='S2')
        active_d7=sum(c['seats'] for c in active if c['g']=='D_S07')
        ncash,new,leads=new_cash_and_cohorts(day,active_s2,active_d7,rng,scenario)
        cash += ncash
        active.extend(new)
        cash -= leadcost_per_day
        newactive=[]
        for c in active:
            cash -= compute_cost_per_seat_day(c,day)*c['seats']
            if day%30 == c['mod']:
                age=day-c['start']
                ret=retention(c['g'],c['plan'],age,rng,scenario,day)
                kept=c['n']*ret; kept_seats=c['seats']*ret
                if kept>0:
                    price=bill_price(c['g'],c['plan'],age,c['price'],day)
                    cash += price*kept_seats
                    cc=c.copy(); cc['n']=kept; cc['seats']=kept_seats; cc['price']=price
                    newactive.append(cc)
            else:
                newactive.append(c)
        active=newactive
        fixed = fixed_high if day < HIGH_UNTIL else fixed_low
        if rel>56:
            # Later operating spend scales down with smaller D_S07 book, up with enterprise seats.
            s2=sum(c['seats'] for c in active if c['g']=='S2')
            d7=sum(c['seats'] for c in active if c['g']=='D_S07')
            entseats=sum(c['seats'] for c in active if c['type']=='large')
            ops = 5000 + 195000*(max(s2,1)/146500)**0.50 + 30000*(max(d7,1)/23400)**0.55 + 10000
            dev = 3000 + 22000*(max(s2,1)/146500)**0.35 + 2500*(max(d7,1)/23400)**0.35 + 8500
            ads = 20000
            cap = 75000 if entseats>250000 or (s2+d7+entseats)>300000 else 28000
            entops = min(90000, 0.10*max(0,entseats-50000))
            fixed = max(275000,min(560000,ops+dev+ads+cap+entops))
        cash -= fixed
    return cash

